CREATE OR REPLACE TRIGGER UpdateCustomerLastModified BEFORE UPDATE ON Customers FOR EACH ROW BEGIN :NEW.LastModified:=SYSDATE; END;/

CREATE TABLE AuditLog(LogID NUMBER GENERATED BY DEFAULT AS IDENTITY,TransactionID NUMBER,LogDate DATE);
CREATE OR REPLACE TRIGGER LogTransaction AFTER INSERT ON Transactions FOR EACH ROW BEGIN INSERT INTO AuditLog(TransactionID,LogDate) VALUES(:NEW.TransactionID,SYSDATE); END;/

CREATE OR REPLACE TRIGGER CheckTransactionRules BEFORE INSERT ON Transactions FOR EACH ROW DECLARE b NUMBER; BEGIN SELECT Balance INTO b FROM Accounts WHERE AccountID=:NEW.AccountID; IF :NEW.TransactionType='Withdrawal' AND :NEW.Amount>b THEN RAISE_APPLICATION_ERROR(-20003,'Insufficient'); ELSIF :NEW.TransactionType='Deposit' AND :NEW.Amount<=0 THEN RAISE_APPLICATION_ERROR(-20004,'Invalid deposit'); END IF; END;/